import json

from a2a.client.client import A2ACardResolver, A2AClient
from a2a.server.tasks.task_manager import TaskManager
from a2a.types import (
    A2ARequest,
    AgentCapabilities,
    AgentCard,
    AgentSkill,
    GetTaskPushNotificationConfigRequest,
    JSONRPCResponse,
    MessageSendParams,
    SetTaskPushNotificationConfigRequest,
    TaskIdParams,
    TaskPushNotificationConfig,
    TaskQueryParams,
    TaskResubscriptionRequest,
)
from fastapi import APIRouter, Request
from pydantic import ValidationError
from starlette.responses import JSONResponse

router = APIRouter()


class MyTaskManager(TaskManager):
    async def dispatch(self, request: A2ARequest) -> JSONRPCResponse:
        request_id = request.root.id
        method = request.root.method
        params = request.root.params

        match method:
            case "tasks/send":
                return await self.on_send_task(params, request_id)
            case "tasks/cancel":
                return await self.on_cancel_task(params, request_id)
            case "tasks/get":
                return await self.on_get_task(params, request_id)
            case "tasks/pushNotification/set":
                return await self.on_set_task_push_notification(params, request_id)
            case "tasks/pushNotification/get":
                return await self.on_get_task_push_notification(params, request_id)
            case "tasks/resubscribe":
                return await self.on_resubscribe_to_task(params, request_id)
            case "tasks/sendSubscribe":
                return await self.on_send_task_subscribe(params, request_id)
            case _:
                return JSONRPCResponse(
                    id=request_id,
                    error=JSONRPCError(code=-32601, message="Method not found"),
                )

    async def on_send_task(
        self, params: MessageSendParams, request_id
    ) -> JSONRPCResponse:
        return JSONRPCResponse(
            id=request_id,
            result=Message(
                messageId="msg-001",
                parts=params.message.parts,
                role=Role.agent,
                type="message",
            ),
        )

    async def on_cancel_task(self, params: TaskIdParams, request_id) -> JSONRPCResponse:
        return JSONRPCResponse(
            id=request_id,
            result=Task(
                id=params.id,
                contextId="ctx-001",
                status={"state": TaskState.canceled},
                type="task",
            ),
        )

    async def on_get_task(self, params: TaskQueryParams, request_id) -> JSONRPCResponse:
        return JSONRPCResponse(
            id=request_id,
            result=Task(
                id=params.id,
                contextId="ctx-001",
                status={"state": TaskState.completed},
                type="task",
            ),
        )

    async def on_get_task_push_notification(
        self, params: TaskIdParams, request_id
    ) -> JSONRPCResponse:
        return JSONRPCResponse(
            id=request_id,
            result={
                "taskId": params.id,
                "pushNotificationConfig": {
                    "url": "http://localhost:8000/push",
                    "token": "abc123",
                    "authentication": {
                        "schemes": ["Bearer"],
                        "credentials": "xyz-token",
                    },
                },
            },
        )

    async def on_set_task_push_notification(
        self, params: TaskPushNotificationConfig, request_id
    ) -> JSONRPCResponse:
        return JSONRPCResponse(id=request_id, result=params)

    async def on_resubscribe_to_task(
        self, params: TaskIdParams, request_id
    ) -> JSONRPCResponse:
        return JSONRPCResponse(
            id=request_id,
            result=Task(
                id=params.id,
                contextId="ctx-001",
                status={"state": TaskState.working},
                type="task",
            ),
        )

    async def on_send_task_subscribe(
        self, params: MessageSendParams, request_id
    ) -> JSONRPCResponse:
        return JSONRPCResponse(
            id=request_id,
            result=Message(
                messageId="msg-002",
                parts=params.message.parts,
                role=Role.agent,
                type="message",
            ),
        )


task_manager = MyTaskManager()


@router.post("/")
async def handle_rpc(request: Request):
